#include <bits/stdc++.h>
using namespace std;
int main(){
    string s; cin >> s;
    stack<char> st;
    auto match=[&](char a,char b){return (a=='('&&b==')')||(a=='['&&b==']')||(a=='{'&&b=='}');};
    for (char c : s) {
        if (c=='('||c=='['||c=='{') st.push(c);
        else { if (st.empty()||!match(st.top(), c)) { cout<<"NO\n"; return 0; } st.pop(); }
    }
    cout << (st.empty() ? "YES" : "NO") << '\n';
}
